  overflow-y: hidden;
}

.toolbar::-webkit-scrollbar {
  height: 3px;
}
.toolbar::-webkit-scrollbar-track { background: transparent; }
.toolbar::-webkit-scrollbar-thumb { background: var(--border-color); border-radius: 2px; }

.toolbar-group {
  display: flex;
  align-items: center;
  gap: 2px;
}

.toolbar-separator {
  width: 1px;
  height: 24px;
  background: var(--border-color);
  margin: 0 6px;
  flex-shrink: 0;
}

.toolbar-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 5px;
  height: 32px;
  min-width: 32px;
  padding: 0 8px;
  background: transparent;
  border: 1px solid transparent;
  border-radius: var(--radius-sm);
  color: var(--text-secondary);
  cursor: pointer;
  font-family: var(--font-sans);
  font-size: 13px;
  font-weight: 500;
  transition: all 0.15s ease;
  white-space: nowrap;
  flex-shrink: 0;
}

.toolbar-btn:hover {
  background: var(--bg-hover);
  border-color: var(--border-color);
  color: var(--text-primary);
}

.toolbar-btn:active {
  background: var(--bg-active);
  border-color: var(--accent-blue);
  color: var(--accent-blue-hover);
  transform: scale(0.96);
}

.toolbar-btn .btn-icon {
  font-size: 15px;
  line-height: 1;
}

/* 헤딩 버튼 특별 스타일 */
.toolbar-btn[data-action="h1"] { color: var(--accent-blue); }
.toolbar-btn[data-action="h2"] { color: var(--accent-purple); }
.toolbar-btn[data-action="h3"] { color: var(--accent-green); }
.toolbar-btn[data-action="h1"]:hover,
.toolbar-btn[data-action="h2"]:hover,
.toolbar-btn[data-action="h3"]:hover {
  color: var(--text-primary);
}

/* 내보내기 버튼 */
.toolbar-spacer {
  flex: 1;
  min-width: 8px;
}

.export-btn {
  display: flex;
  align-items: center;
  gap: 6px;
  height: 32px;
  padding: 0 14px;
  background: var(--accent-blue);
  border: none;
  border-radius: var(--radius-sm);
  color: #ffffff;
  cursor: pointer;
  font-family: var(--font-sans);
  font-size: 13px;
  font-weight: 600;
  transition: all 0.15s ease;
  flex-shrink: 0;
}

.export-btn:hover {
  background: var(--accent-blue-hover);
  box-shadow: var(--shadow-sm);
}

.export-btn:active {
  transform: scale(0.97);
}

/* ============================
   에디터 컨테이너
   ============================ */
.editor-container {
  display: flex;
  flex: 1;
  overflow: hidden;
  min-height: 0;
}

/* ============================
   에디터 창
   ============================ */
.pane {
  display: flex;
  flex-direction: column;
  overflow: hidden;
  min-width: 150px;
}

#editor-pane {
  flex: 1;
}

#preview-pane {
  flex: 1;
  border-left: 1px solid var(--border-color);
}

.pane-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 36px;
  padding: 0 16px;
  background: var(--bg-secondary);
  border-bottom: 1px solid var(--border-muted);
  flex-shrink: 0;
}

.pane-title {
  font-size: 12px;
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.6px;
}

.pane-meta {
  font-size: 11px;
  color: var(--text-muted);
}

/* 에디터 텍스트영역 */
#editor-textarea {
  flex: 1;
  width: 100%;
  padding: 20px 24px;
  background: var(--bg-primary);
  border: none;
  outline: none;
  resize: none;
  font-family: var(--font-mono);
  font-size: 14px;
  line-height: 1.7;
  color: var(--text-primary);
  caret-color: var(--accent-blue);
  tab-size: 2;
  overflow-y: auto;
}

#editor-textarea::placeholder {
  color: var(--text-muted);
}

#editor-textarea::-webkit-scrollbar { width: 6px; }
#editor-textarea::-webkit-scrollbar-track { background: transparent; }
#editor-textarea::-webkit-scrollbar-thumb {
  background: var(--border-color);
  border-radius: 3px;
}
#editor-textarea::-webkit-scrollbar-thumb:hover { background: var(--bg-hover); }

/* ============================
   크기 조절 바 (Resizer)
   ============================ */
.resizer {
  width: 5px;
  background: var(--resizer-color);
  cursor: col-resize;
  flex-shrink: 0;
  position: relative;
  transition: background 0.2s ease;
  z-index: 10;
}

.resizer::after {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 3px;
  height: 32px;
  background: var(--border-color);
  border-radius: 2px;
  transition: all 0.2s ease;
}

.resizer:hover,
.resizer:active {
  background: var(--resizer-hover);
}

.resizer:hover::after,
.resizer:active::after {
  background: var(--accent-blue);
  width: 3px;
  height: 48px;
}

/* ============================
   미리보기 창
   ============================ */
.preview-scroll {
  flex: 1;
  overflow-y: auto;
  padding: 24px 32px;
  background: var(--bg-primary);
}

.preview-scroll::-webkit-scrollbar { width: 6px; }
.preview-scroll::-webkit-scrollbar-track { background: transparent; }
.preview-scroll::-webkit-scrollbar-thumb {
  background: var(--border-color);
  border-radius: 3px;
}
.preview-scroll::-webkit-scrollbar-thumb:hover { background: var(--bg-hover); }

/* ============================
   미리보기 콘텐츠 (GitHub 스타일)
   ============================ */
#preview-content {
  max-width: 760px;
  margin: 0 auto;
  color: var(--text-primary);
  font-family: var(--font-sans);
  font-size: 15px;
  line-height: 1.75;
}

/* 제목 */
#preview-content h1,
#preview-content h2,
#preview-content h3,
#preview-content h4,
#preview-content h5,
#preview-content h6 {
  margin-top: 1.75rem;
  margin-bottom: 0.75rem;
  font-weight: 700;
  line-height: 1.35;
  color: var(--text-primary);
}

#preview-content h1:first-child,
#preview-content h2:first-child,
#preview-content h3:first-child {
  margin-top: 0;
}

#preview-content h1 {
  font-size: 2rem;
  border-bottom: 2px solid var(--border-color);
  padding-bottom: 0.4rem;
}

#preview-content h2 {
  font-size: 1.5rem;
  border-bottom: 1px solid var(--border-muted);
  padding-bottom: 0.3rem;
}

#preview-content h3 { font-size: 1.25rem; }
#preview-content h4 { font-size: 1.1rem; }
#preview-content h5 { font-size: 1rem; }
#preview-content h6 {
  font-size: 0.9rem;
  color: var(--text-secondary);
}

/* 단락 */
#preview-content p {
  margin-bottom: 1rem;
  color: var(--text-primary);
}

/* 굵게, 기울임 */
#preview-content strong {
  font-weight: 700;
  color: var(--text-primary);
}

#preview-content em {
  font-style: italic;
}

/* 인라인 코드 */
#preview-content code {
  font-family: var(--font-mono);
  font-size: 85%;
  background: var(--bg-tertiary);
  padding: 0.2em 0.45em;
  border-radius: var(--radius-sm);
  color: #ff7b72;
  border: 1px solid var(--border-muted);
}

/* 코드 블록 */
#preview-content pre {
  position: relative;
  background: var(--bg-secondary);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  padding: 1.25rem 1.5rem;
  margin-bottom: 1rem;
  overflow-x: auto;
}

#preview-content pre::-webkit-scrollbar { height: 5px; }
#preview-content pre::-webkit-scrollbar-track { background: transparent; }
#preview-content pre::-webkit-scrollbar-thumb {
  background: var(--border-color);
  border-radius: 3px;
}

#preview-content pre code {
  background: none;
  border: none;
  padding: 0;
  font-size: 13px;
  color: var(--text-primary);
  line-height: 1.65;
  white-space: pre;
}

/* 언어 레이블 */
#preview-content .code-lang {
  position: absolute;
  top: 0;
  right: 0;
  padding: 2px 10px;
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-muted);
  background: var(--bg-tertiary);
  border-bottom-left-radius: var(--radius-sm);
  border-top-right-radius: var(--radius-md);
  border-left: 1px solid var(--border-muted);
  border-bottom: 1px solid var(--border-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

/* 링크 */
#preview-content a {
  color: var(--accent-blue-hover);
  text-decoration: none;
  border-bottom: 1px solid transparent;
  transition: border-color 0.15s ease;
}

#preview-content a:hover {
  border-bottom-color: var(--accent-blue-hover);
}

/* 이미지 */
#preview-content img {
  max-width: 100%;
  border-radius: var(--radius-md);
  border: 1px solid var(--border-color);
  display: block;
  margin: 0.5rem auto;
}

/* 목록 */
#preview-content ul,
#preview-content ol {
  padding-left: 1.75rem;
  margin-bottom: 1rem;
}

#preview-content li {
  margin-bottom: 0.3rem;
}

#preview-content li > ul,
#preview-content li > ol {
  margin-top: 0.3rem;
  margin-bottom: 0;
}

#preview-content ul li::marker {
  color: var(--text-muted);
}

#preview-content ol li::marker {
  color: var(--text-secondary);
  font-weight: 600;
}

/* 인용문 */
#preview-content blockquote {
  border-left: 4px solid var(--accent-blue);
  margin: 0 0 1rem 0;
  padding: 0.5rem 1rem;
  background: var(--bg-secondary);
  border-radius: 0 var(--radius-sm) var(--radius-sm) 0;
  color: var(--text-secondary);
}

#preview-content blockquote p {
  margin-bottom: 0;
  color: var(--text-secondary);
}

#preview-content blockquote blockquote {
  margin-top: 0.5rem;
  border-left-color: var(--accent-purple);
}

/* 수평선 */
#preview-content hr {
  border: none;
  border-top: 2px solid var(--border-color);
  margin: 1.75rem 0;
}

/* 줄바꿈 */
#preview-content br {
  display: block;
  content: '';
  margin-bottom: 0.25rem;
}

/* ============================
   상태 바
   ============================ */
.statusbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: var(--statusbar-height);
  padding: 0 16px;
  background: var(--accent-blue);
  flex-shrink: 0;
}

.statusbar-left,
.statusbar-right {
  display: flex;
  align-items: center;
  gap: 16px;
}

.statusbar-item {
  font-size: 12px;
  color: rgba(255, 255, 255, 0.9);
  font-weight: 500;
}

.statusbar-item strong {
  color: #ffffff;
}

/* ============================
   스크롤바 (전역)
   ============================ */
::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb {
  background: var(--border-color);
  border-radius: 3px;
}
::-webkit-scrollbar-thumb:hover { background: var(--bg-hover); }

/* ============================
   반응형 레이아웃
   ============================ */
@media (max-width: 768px) {
  .editor-container {
    flex-direction: column;
  }

  #editor-pane,
  #preview-pane {
    flex: 1;
    width: 100% !important;
    border-left: none;
    border-bottom: 1px solid var(--border-color);
  }

  .resizer {
    width: 100%;
    height: 5px;
    cursor: row-resize;
  }

  .resizer::after {
    width: 32px;
    height: 3px;
  }

  .toolbar {
    padding: 0 8px;
    gap: 1px;
  }

  .toolbar-btn {
    padding: 0 6px;
    font-size: 12px;
  }

  .preview-scroll {
    padding: 16px;
  }
}

/* ============================
   애니메이션
   ============================ */
@keyframes fadeIn {
  from { opacity: 0; transform: translateY(4px); }
  to { opacity: 1; transform: translateY(0); }
}

#preview-content {
  animation: fadeIn 0.15s ease;
}

/* 포커스 스타일 */
#editor-textarea:focus {
  box-shadow: inset 2px 0 0 var(--accent-blue);
}

/* 선택 스타일 */
#editor-textarea::selection {
  background: rgba(56, 139, 253, 0.3);
}

/* 툴팁 (title 속성 기반) */
.toolbar-btn[title] {
  position: relative;
}

