    text = text.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, (_, alt, src) => `<img src="${escapeHtml(src)}" alt="${escapeHtml(alt)}">`);

    // 링크
    text = text.replace(/\[([^\]]+)\]\(([^)]+)\)/g, (_, linkText, href) => `<a href="${escapeHtml(href)}" target="_blank" rel="noopener noreferrer">${linkText}</a>`);

