    while (i < lines.length) {
      const line = lines[i];
      const unorderedMatch = line.match(/^(\s*)([-*+])\s+(.+)/);
      const orderedMatch = line.match(/^(\s*)(\d+)\.\s+(.+)/);
      const match = unorderedMatch || orderedMatch;

      if (!match) break;

      const indent = match[1].length;
      if (indent < baseIndent) break;

