   203→assert(bqNested.match(/<blockquote>/g).length >= 2, '중첩 인용문 내부');
   204→
   205→const bqInline = parse('> **굵게** 인용');
   206→assertContains(bqInline, '<strong>굵게</strong>', '인용문 내 인라인 서식');
   207→
   208→// =====================================================================
   209→// 9. 파서 - 수평선
   210→// =====================================================================
   211→section('파서: 수평선');
   212→
   213→assertEqual(parse('---'), '<hr>', '--- 수평선');
   214→assertEqual(parse('***'), '<hr>', '*** 수평선');
