   218→
   219→// =====================================================================
   220→// 10. 파서 - 단락 & 줄바꿈
   221→// =====================================================================
   222→section('파서: 단락 & 줄바꿈');
   223→
   224→const para = parse('첫 번째 단락\n\n두 번째 단락');
   225→assertContains(para, '<p>첫 번째 단락</p>', '첫 번째 단락');
   226→assertContains(para, '<p>두 번째 단락</p>', '두 번째 단락');
   227→
   228→const lineBreak = parse('첫째 줄  \n둘째 줄');
   229→assertContains(lineBreak, '<br>', '두 칸 공백 줄바꿈');
   230→
   231→// =====================================================================
   232→// 11. 파서 - 이스케이프 문자
   233→// =====================================================================
   234→section('파서: 이스케이프 문자');
   235→
   236→assert(parse('\\*별표\\*').includes('*별표*') && !parse('\\*별표\\*').includes('<em>'), '\\* 이스케이프');
   237→assert(parse('\\**굵게아님\\**').includes('**굵게아님**') || !parse('\\**굵게아님\\**').includes('<strong>'), '\\** 이스케이프');
   238→assert(parse('\\`코드아님\\`').includes('`코드아님`'), '\\` 이스케이프');
   239→assert(parse('\\# 제목아님').includes('# 제목아님') || !parse('\\# 제목아님').includes('<h1'), '\\# 이스케이프');
   240→
   241→// HTML 이스케이프
   242→assertContains(parse('<script>alert()</script>'), '&lt;script&gt;', 'HTML 태그 이스케이프');
   243→assertContains(parse('a & b'), '&amp;', '& 이스케이프');
   244→
   245→// =====================================================================
   246→// 12. 파서 - 엣지 케이스
   247→// =====================================================================
   248→section('파서: 엣지 케이스');
   249→
   250→assertEqual(parse(''), '', '빈 입력');
   251→assertEqual(parse('   '), '', '공백만 있는 입력');
   252→assertEqual(parse('\n\n\n'), '', '개행만 있는 입력');
   253→
   254→// 닫히지 않은 마크다운 마커 - 그대로 출력
   255→assert(!parse('**닫히지않음').includes('<strong>') || parse('**닫히지않음').includes('**닫히지않음'), '닫히지 않은 ** 처리');
   256→assert(!parse('*닫히지않음').includes('<em>') || parse('*닫히지않음').includes('닫히지않음'), '닫히지 않은 * 처리');
   257→
   258→// 잘못된 링크
   259→const malformedLink = parse('[링크]');
   260→assert(!malformedLink.includes('<a '), '괄호 없는 링크는 a 태그 아님');
   261→
   262→// 연속 헤딩
   263→const consecutiveH = parse('# 제목1\n## 제목2\n### 제목3');
   264→assertContains(consecutiveH, '<h1', '연속 헤딩 h1');
   265→assertContains(consecutiveH, '<h2', '연속 헤딩 h2');
   266→assertContains(consecutiveH, '<h3', '연속 헤딩 h3');
   267→
   268→// 혼합 인라인 서식
   269→const mixed = parse('**굵게** 그리고 *기울임* 그리고 `코드`');
   270→assertContains(mixed, '<strong>굵게</strong>', '혼합 서식: 굵게');
   271→assertContains(mixed, '<em>기울임</em>', '혼합 서식: 기울임');
   272→assertContains(mixed, '<code>코드</code>', '혼합 서식: 코드');
   273→
   274→// `- ` (내용 없는 항목)은 목록으로 처리되지 않고 단락으로 fallback
   275→const emptyLi = parse('- \n- 내용');
   276→assert(!emptyLi.includes('<li></li>'), '빈 - 는 빈 li를 생성하지 않음');
   277→assertContains(emptyLi, '내용', '빈 항목 다음 유효한 항목 렌더링');
   278→
   279→// ul 다음 ol은 각각 별도 목록으로 렌더링
   280→const mixedList = parse('- ul 항목\n1. ol 항목');
   281→assertContains(mixedList, '<ul>', '혼합 목록 ul 부분');
   282→assertContains(mixedList, '<ol>', '혼합 목록 ol 부분');
   283→
   284→// 제목 안 특수 문자
   285→const headingSpecial = parse('# Hello & World <test>');
   286→assertContains(headingSpecial, '&amp;', '제목 안 & 이스케이프');
   287→assertContains(headingSpecial, '&lt;', '제목 안 < 이스케이프');
   288→
   289→// =====================================================================
   290→// 13. 툴바 동작 - DOM 모킹으로 에디터 로드
   291→// =====================================================================
   292→section('툴바 동작: DOM 모킹');
   293→
   294→// Mock DOM 구성
   295→const mockStorage = {};
   296→const mockEventListeners = {};
   297→
   298→// 모의 텍스트영역
   299→function makeMockTextarea(value = '') {
   300→  return {
   301→    value,
   302→    selectionStart: 0,
   303→    selectionEnd: 0,
   304→    _listeners: {},
   305→    addEventListener(event, fn) {
   306→      if (!this._listeners[event]) this._listeners[event] = [];
   307→      this._listeners[event].push(fn);
   308→    },
   309→    setSelectionRange(start, end) {
   310→      this.selectionStart = start;
   311→      this.selectionEnd = end;
   312→    },
   313→    focus() {},
   314→    // 선택 영역 설정 헬퍼
   315→    select(start, end) {
   316→      this.selectionStart = start;
   317→      this.selectionEnd = end;
   318→    },
   319→  };
   320→}
   321→
   322→// 툴바 액션을 직접 구현하여 테스트 (에디터 내부 로직 반영)
   323→function makeInsertAtCursor(textarea) {
   324→  return function insertAtCursor(before, after = '', defaultText = '') {
   325→    const start = textarea.selectionStart;
   326→    const end = textarea.selectionEnd;
   327→    const selected = textarea.value.substring(start, end);
   328→    const text = selected || defaultText;
   329→    const newText = before + text + after;
   330→    textarea.value = textarea.value.substring(0, start) + newText + textarea.value.substring(end);
   331→    const newStart = start + before.length;
   332→    const newEnd = newStart + text.length;
   333→    textarea.setSelectionRange(newStart, newEnd);
   334→  };
   335→}
   336→
   337→function makeInsertLinePrefix(textarea) {
   338→  return function insertLinePrefix(prefix) {
   339→    const start = textarea.selectionStart;
   340→    const end = textarea.selectionEnd;
   341→    const value = textarea.value;
   342→    const lineStart = value.lastIndexOf('\n', start - 1) + 1;
   343→    const selectedText = value.substring(lineStart, end);
   344→    const lines = selectedText.split('\n');
   345→    const newLines = lines.map(line => {
   346→      if (line.startsWith(prefix)) return line.substring(prefix.length);
   347→      return prefix + line;
   348→    });
   349→    const newSelected = newLines.join('\n');
   350→    textarea.value = value.substring(0, lineStart) + newSelected + value.substring(end);
   351→    textarea.setSelectionRange(lineStart, lineStart + newSelected.length);
   352→  };
   353→}
   354→
   355→// 굵게 버튼
   356→{
   357→  const ta = makeMockTextarea('Hello World');
   358→  const insert = makeInsertAtCursor(ta);
   359→  ta.select(6, 11); // "World" 선택
   360→  insert('**', '**', '굵은 텍스트');
   361→  assertEqual(ta.value, 'Hello **World**', '굵게: 선택 텍스트 래핑');
   362→}
   363→
   364→{
   365→  const ta = makeMockTextarea('');
   366→  const insert = makeInsertAtCursor(ta);
   367→  ta.select(0, 0);
   368→  insert('**', '**', '굵은 텍스트');
   369→  assertEqual(ta.value, '**굵은 텍스트**', '굵게: 선택 없을 때 기본 텍스트 삽입');
   370→  assertEqual(ta.selectionStart, 2, '굵게 삽입 후 커서 시작 위치');
   371→  assertEqual(ta.selectionEnd, 8, '굵게 삽입 후 커서 끝 위치 (기본텍스트 선택)'); // '굵은 텍스트' = 6자 → 2+6=8
   372→}
   373→
   374→// 기울임 버튼
   375→{
   376→  const ta = makeMockTextarea('안녕 세상');
   377→  const insert = makeInsertAtCursor(ta);
   378→  ta.select(3, 5); // "세상" 선택
   379→  insert('*', '*', '기울임 텍스트');
   380→  assertEqual(ta.value, '안녕 *세상*', '기울임: 선택 텍스트 래핑');
   381→}
   382→
   383→// h1 버튼
   384→{
   385→  const ta = makeMockTextarea('제목');
   386→  const prefix = makeInsertLinePrefix(ta);
   387→  ta.select(0, 2);
   388→  prefix('# ');
   389→  assertEqual(ta.value, '# 제목', 'h1: 줄 앞에 # 추가');
   390→}
   391→
   392→// h2 버튼
   393→{
   394→  const ta = makeMockTextarea('제목');
   395→  const prefix = makeInsertLinePrefix(ta);
   396→  ta.select(0, 2);
   397→  prefix('## ');
   398→  assertEqual(ta.value, '## 제목', 'h2: 줄 앞에 ## 추가');
   399→}
   400→
   401→// h3 버튼
   402→{
   403→  const ta = makeMockTextarea('제목');
   404→  const prefix = makeInsertLinePrefix(ta);
   405→  ta.select(0, 2);
   406→  prefix('### ');
   407→  assertEqual(ta.value, '### 제목', 'h3: 줄 앞에 ### 추가');
   408→}
   409→
   410→// 토글 동작 (이미 접두사가 있으면 제거)
   411→{
   412→  const ta = makeMockTextarea('# 이미 h1');
   413→  const prefix = makeInsertLinePrefix(ta);
   414→  ta.select(0, 8);
   415→  prefix('# ');
   416→  assertEqual(ta.value, '이미 h1', 'h1: 이미 있는 # 제거 (토글)');
   417→}
   418→
   419→// 인라인 코드
   420→{
   421→  const ta = makeMockTextarea('변수');
   422→  const insert = makeInsertAtCursor(ta);
   423→  ta.select(0, 2);
   424→  insert('`', '`', '코드');
   425→  assertEqual(ta.value, '`변수`', '코드: 선택 텍스트 래핑');
   426→}
   427→
   428→// 순서 없는 목록
   429→{
   430→  const ta = makeMockTextarea('항목');
   431→  const prefix = makeInsertLinePrefix(ta);
   432→  ta.select(0, 2);
   433→  prefix('- ');
   434→  assertEqual(ta.value, '- 항목', '목록: - 접두사 추가');
   435→}
   436→
   437→// 인용문
   438→{
   439→  const ta = makeMockTextarea('인용할 내용');
   440→  const prefix = makeInsertLinePrefix(ta);
   441→  ta.select(0, 6);
   442→  prefix('> ');
   443→  assertEqual(ta.value, '> 인용할 내용', '인용문: > 접두사 추가');
   444→}
   445→
   446→// 다중 줄 선택 접두사
   447→{
   448→  const ta = makeMockTextarea('줄1\n줄2\n줄3');
   449→  const prefix = makeInsertLinePrefix(ta);
   450→  ta.select(0, 7); // "줄1\n줄2" 선택
   451→  prefix('# ');
   452→  assertContains(ta.value, '# 줄1', '다중 줄 h1: 첫 번째 줄');
   453→  assertContains(ta.value, '# 줄2', '다중 줄 h1: 두 번째 줄');
   454→}
   455→
   456→// =====================================================================
   457→// 14. 에디터 상태 - localStorage 저장/복원
   458→// =====================================================================
   459→section('에디터 상태: localStorage');
   460→
   461→// 모의 localStorage
   462→const mockLS = (() => {
   463→  const store = {};
   464→  return {
   465→    getItem: (k) => (k in store ? store[k] : null),
   466→    setItem: (k, v) => { store[k] = String(v); },
   467→    removeItem: (k) => { delete store[k]; },
   468→    clear: () => { Object.keys(store).forEach(k => delete store[k]); },
   469→  };
   470→})();
   471→
   472→const STORAGE_KEY = 'md-editor-content';
   473→
   474→// 저장 테스트
   475→mockLS.setItem(STORAGE_KEY, '# 저장된 내용');
   476→assertEqual(mockLS.getItem(STORAGE_KEY), '# 저장된 내용', 'localStorage 저장 확인');
   477→
   478→// 복원 테스트
   479→const restored = mockLS.getItem(STORAGE_KEY);
   480→assertEqual(restored, '# 저장된 내용', 'localStorage 복원 확인');
   481→
   482→// 키 없을 때 null 반환
   483→mockLS.clear();
   484→assertEqual(mockLS.getItem(STORAGE_KEY), null, '키 없을 때 null 반환');
   485→
   486→// 저장 내용이 실제 마크다운인지 확인
   487→const sampleMd = '# 제목\n\n**굵게** 텍스트\n\n- 항목1\n- 항목2';
   488→mockLS.setItem(STORAGE_KEY, sampleMd);
   489→assertEqual(mockLS.getItem(STORAGE_KEY), sampleMd, '마크다운 내용 온전히 저장');
   490→
   491→// =====================================================================
   492→// 15. HTML 내보내기 - 출력 구조 검증
   493→// =====================================================================
   494→section('HTML 내보내기: 출력 구조');
   495→
   496→// 내보내기 로직 직접 테스트 (exportHtml 내부 HTML 생성 로직)
   497→function buildExportHtml(previewContent) {
   498→  return `<!DOCTYPE html>
   499→<html lang="ko">
   500→<head>
   501→  <meta charset="UTF-8">
   502→  <meta name="viewport" content="width=device-width, initial-scale=1.0">
   503→  <title>마크다운 문서</title>
   504→  <style>
   505→    body { font-family: -apple-system, sans-serif; max-width: 800px; margin: 0 auto; padding: 2rem; }
   506→  </style>
   507→</head>
   508→<body>
   509→${previewContent}
   510→</body>
   511→</html>`;
   512→}
   513→
   514→const sampleMarkdown = '# 제목\n\n단락 내용\n\n- 항목1\n- 항목2';
   515→const renderedHtml = parser.parse(sampleMarkdown);
   516→const exported = buildExportHtml(renderedHtml);
   517→
   518→assertContains(exported, '<!DOCTYPE html>', '내보내기: DOCTYPE 선언');
   519→assertContains(exported, '<meta charset="UTF-8">', '내보내기: 문자셋 메타태그');
   520→assertContains(exported, '<html lang="ko">', '내보내기: 언어 속성');
   521→assertContains(exported, '<title>마크다운 문서</title>', '내보내기: 제목 태그');
   522→assertContains(exported, '<style>', '내보내기: 스타일 포함');
   523→assertContains(exported, '<h1', '내보내기: 마크다운 제목 렌더링');
   524→assertContains(exported, '<p>단락 내용</p>', '내보내기: 단락 렌더링');
   525→assertContains(exported, '<ul>', '내보내기: 목록 렌더링');
   526→assertContains(exported, '</html>', '내보내기: HTML 종료 태그');
   527→
   528→// 렌더링된 콘텐츠가 완전한 HTML 문서에 포함됨
   529→const bodyMatch = exported.match(/<body>([\s\S]*?)<\/body>/);
   530→assert(bodyMatch !== null, '내보내기: body 태그 존재');
   531→assert(bodyMatch[1].includes('<h1'), '내보내기: body 안에 h1 태그');
   532→
   533→// XSS 방지 - 스크립트 태그 이스케이프
   534→const xssMarkdown = '<script>alert("XSS")</script>';
   535→const xssRendered = parser.parse(xssMarkdown);
   536→const xssExported = buildExportHtml(xssRendered);
   537→assert(!xssExported.includes('<script>alert'), '내보내기: XSS 스크립트 이스케이프');
   538→
   539→// =====================================================================
   540→// 결과 요약
   541→// =====================================================================
   542→process.stdout.write('\n' + '='.repeat(50) + '\n');
   543→process.stdout.write(`테스트 결과: ${passed + failed}개 중 ${passed}개 통과\n`);
   544→
   545→if (failures.length > 0) {
   546→  process.stdout.write('\n실패한 테스트:\n');
   547→  failures.forEach(f => process.stdout.write('  - ' + f + '\n'));
   548→}
   549→
   550→process.stdout.write('='.repeat(50) + '\n');
   551→process.exit(failed > 0 ? 1 : 0);
   552→

