  assertEqual(ta.selectionStart, 2, '굵게 삽입 후 커서 시작 위치');
  assertEqual(ta.selectionEnd, 8, '굵게 삽입 후 커서 끝 위치 (기본텍스트 선택)'); // '굵은 텍스트' = 6자 → 2+6=8
}

// 기울임 버튼
{
  const ta = makeMockTextarea('안녕 세상');
  const insert = makeInsertAtCursor(ta);
  ta.select(3, 5); // "세상" 선택
